// Compute this week's stats vs last week, then build the Claude digest request.
const DAY = 86400000;
const now = Date.now();
const rows = $input.all().map(i => i.json).filter(r => r && r.source_url);
const age = r => now - new Date(r.scraped_at).getTime();
const thisWeek = rows.filter(r => age(r) <= 7 * DAY);
const prevWeek = rows.filter(r => age(r) > 7 * DAY && age(r) <= 14 * DAY);

function summarize(set) {
  const byRole = {};
  for (const r of set) {
    const k = r.role_category || 'other';
    byRole[k] = byRole[k] || { postings: 0, stipends: [], skills: {} };
    byRole[k].postings++;
    if (r.stipend_min_inr) byRole[k].stipends.push(r.stipend_min_inr);
    for (const s of (r.skills || [])) byRole[k].skills[s] = (byRole[k].skills[s] || 0) + 1;
  }
  for (const k of Object.keys(byRole)) {
    const st = byRole[k].stipends;
    byRole[k].avg_stipend = st.length ? Math.round(st.reduce((a, b) => a + b, 0) / st.length) : null;
    byRole[k].top_skills = Object.entries(byRole[k].skills).sort((a, b) => b[1] - a[1]).slice(0, 6);
    delete byRole[k].stipends;
    delete byRole[k].skills;
  }
  return byRole;
}

// Skill deltas across all roles
function skillCounts(set) {
  const c = {};
  for (const r of set) for (const s of (r.skills || [])) c[s] = (c[s] || 0) + 1;
  return c;
}
const cur = skillCounts(thisWeek);
const prev = skillCounts(prevWeek);
const deltas = Object.keys({ ...cur, ...prev })
  .map(s => ({ skill: s, this_week: cur[s] || 0, last_week: prev[s] || 0 }))
  .filter(d => d.this_week + d.last_week >= 3)
  .sort((a, b) => Math.abs(b.this_week - b.last_week) - Math.abs(a.this_week - a.last_week))
  .slice(0, 10);

const topStipend = thisWeek
  .filter(r => r.stipend_max_inr)
  .sort((a, b) => b.stipend_max_inr - a.stipend_max_inr)
  .slice(0, 5)
  .map(r => ({ title: r.title, company: r.company, stipend_max_inr: r.stipend_max_inr, city: r.city || 'remote' }));

const SYSTEM = 'You write "CampusCompass Weekly" - a sharp, data-driven Telegram digest about the Indian internship market for PM / Growth / Analyst / Software roles, read by college students. Voice: smart friend who reads the data so they do not have to. No corporate fluff, no motivational filler. Format (Telegram HTML, <b></b> for bold only, NO markdown): 1) one-line hook stat, 2) \ud83d\udcca <b>By the numbers</b> - postings per role, avg stipend, deltas vs last week, 3) \ud83d\udcc8 <b>Skills moving</b> - 2-3 skills rising or falling with numbers, 4) \ud83d\udcb0 <b>Stipend watch</b> - best-paying postings this week, 5) \ud83c\udfaf <b>If you are prepping</b> - ONE concrete actionable takeaway. Under 250 words. Every claim must come from the data provided - never invent numbers. If data is thin, say so plainly and keep it short.';

const payload = {
  this_week_by_role: summarize(thisWeek),
  last_week_by_role: summarize(prevWeek),
  skill_deltas: deltas,
  top_stipends_this_week: topStipend,
  total_postings_tracked: rows.length
};

return [{ json: { anthropic_body: {
  model: 'claude-sonnet-5',
  max_tokens: 3000,
  thinking: { type: 'disabled' },
  system: SYSTEM,
  messages: [{ role: 'user', content: `This week's data (last 7 days), JSON:\n${JSON.stringify(payload, null, 1)}\n\nWrite this week's digest. Today: ${new Date().toISOString().slice(0, 10)}.` }]
} } }];
